string Resizer::makeUniqueNetName()
{
  string node_name;
  Instance* top_inst = network_->topInstance();
  do {
    stringPrint(node_name, "net%d", unique_net_index_++);
  } while (network_->findNet(top_inst, node_name.c_str()));
  return node_name;
