  }
}

bool Resizer::isFuncOneZero(const Pin* drvr_pin)
{
  LibertyPort* port = network_->libertyPort(drvr_pin);
  if (port) {
    FuncExpr* func = port->function();
    return func
           && (func->op() == FuncExpr::op_zero
               || func->op() == FuncExpr::op_one);
  }
  return false;
}

